1. /**
2.  * @mobile — Mobile viewport smoke tests.
3.  *
4.  * These tests verify critical UX requirements on small screens:
5.  * - Touch targets meet the 44 × 44 px minimum (WCAG 2.5.5)
6.  * - The numeric session-code input uses inputMode="numeric" (fast numpad)
7.  * - The join flow completes successfully on a phone viewport
8.  *
9.  * Tags: @mobile, @smoke
10.  *
11.  * These tests are automatically included in the mobile-chrome and mobile-safari
12.  * Playwright projects via the `grep: /@mobile/` filter in playwright.config.ts.
13.  */
14. import { test, expect } from '@playwright/test';
15. 
16. test.describe('Mobile UX', () => {
17.   test.beforeEach(async ({ page }) => {
18.     await page.goto('/');
19.   });
20. 
21.   test('Home page — buttons are tappable (≥ 44 px) @mobile @smoke', async ({ page }) => {
22.     // Scope to main to avoid NavBar links (e.g. "Host a Game") matching the same name
23.     const main = page.getByRole('main');
24.     const hostBtn = main.getByRole('link', { name: /host/i });
25.     const joinBtn = main.getByRole('link', { name: /join|participant/i });
26. 
27.     for (const btn of [hostBtn, joinBtn]) {
28.       const box = await btn.boundingBox();
29.       expect(box, 'Button must be visible').not.toBeNull();
30.       expect(
31.         box!.height,
32.         `Button "${await btn.textContent()}" height must be ≥ 44 px`,
33.       ).toBeGreaterThanOrEqual(44);
34.       expect(
35.         box!.width,
36.         `Button "${await btn.textContent()}" width must be ≥ 44 px`,
37.       ).toBeGreaterThanOrEqual(44);
38.     }
39.   });
40. 
41.   test('Join page — session code input uses numeric keyboard @mobile @smoke', async ({ page }) => {
42.     await page.goto('/play');
43. 
44.     // Wait for React hydration
45.     const input = page.getByLabel(/tasting code/i);
46.     await expect(input).toBeVisible();
47. 
48.     const inputMode = await input.getAttribute('inputmode');
49.     expect(
50.       inputMode,
51.       'Tasting code field must have inputmode="numeric" so mobile users get a numpad',
52.     ).toBe('numeric');
53.   });
54. 
55.   test('Join flow completes on mobile viewport @mobile', async ({ page }) => {
56.     // We need a real session to join — skip gracefully if PartyKit is unavailable
57.     const partyRes = await page.request.get('http://localhost:1999/').catch(() => null);
58.     if (!partyRes || partyRes.status() >= 500) {
59.       test.skip(true, 'PartyKit not reachable — skipping mobile join flow');
60.     }
61. 
62.     await page.goto('/play');
63. 
64.     await test.step('Navigate to join page', async () => {
65.       await expect(page.getByLabel(/tasting code/i)).toBeVisible();
66.     });
67. 
68.     await test.step('Verify page is usable within mobile viewport', async () => {
69.       // Confirm the join form fits within the viewport without horizontal scroll
70.       const scrollWidth: number = await page.evaluate(() => document.documentElement.scrollWidth);
71.       const clientWidth: number = await page.evaluate(() => document.documentElement.clientWidth);
72.       expect(
73.         scrollWidth,
74.         'Page must not require horizontal scrolling on mobile',
75.       ).toBeLessThanOrEqual(clientWidth + 1); // +1 px tolerance for sub-pixel rounding
76.     });
77.   });
78. 
79.   test('NavBar URL span is visible at 375px viewport (no hidden class) @mobile @smoke', async ({ page }) => {
80.     await page.goto('/');
81.     // The NavBar brand text uses 'hidden sm:inline' (hidden on mobile, visible on sm+).
82.     // Verify exactly 1 such span exists (the Sommelier Arena brand text) — not more.
83.     const hiddenSpan = page.locator('nav span.hidden');
84.     await expect(hiddenSpan).toHaveCount(1);
85.     // Verify the NavBar itself is still visible at mobile width
86.     await expect(page.getByRole('navigation')).toBeVisible();
87.   });
88. });
89.

