1. import React from 'react';
2. import { Timer } from '../common/Timer';
3. import type { QuestionPayload } from '../../types/events';
4. 
5. const CATEGORY_LABELS: Record<string, string> = {
6.   color: 'Color',
7.   region: 'Region',
8.   grape_variety: 'Grape Variety',
9.   vintage_year: 'Vintage Year',
10.   wine_name: 'Wine Name',
11. };
12. 
13. interface QuestionViewProps {
14.   question: QuestionPayload;
15.   selectedOptionId: string | null;
16.   timerMs: number;
17.   onSelect: (optionId: string) => void;
18. }
19. 
20. export function QuestionView({
21.   question,
22.   selectedOptionId,
23.   timerMs,
24.   onSelect,
25. }: QuestionViewProps) {
26.   return (
27.     <div className="min-h-screen bg-slate-50 flex flex-col px-4 py-8">
28.       <div className="w-full max-w-lg mx-auto flex-1 flex flex-col gap-5">
29.         {/* Header */}
30.         <div className="flex items-center justify-between">
31.           <span className="text-xs font-medium bg-slate-100 text-slate-500 rounded-full px-3 py-1">
32.             {CATEGORY_LABELS[question.category] ?? question.category}
33.           </span>
34.           <div className="text-sm text-slate-400">
35.             R{question.roundIndex + 1} · Q{question.questionIndex + 1}/{question.totalQuestions}
36.           </div>
37.         </div>
38. 
39.         {/* Timer */}
40.         <div className="flex justify-center">
41.           <Timer remainingMs={timerMs} />
42.         </div>
43. 
44.         {/* Question prompt */}
45.         <div className="bg-white border border-slate-200 rounded-2xl p-5">
46.           <p className="text-xl font-semibold text-slate-800 text-center">
47.             {question.prompt}
48.           </p>
49.         </div>
50. 
51.         {/* Options — 2×2 grid: A+B on row 1, C+D on row 2 */}
52.         <div className="grid grid-cols-2 gap-3 flex-1">
53.           {question.options.map((opt, i) => {
54.             const isSelected = opt.id === selectedOptionId;
55.             return (
56.               <button
57.                 key={opt.id}
58.                 onClick={() => onSelect(opt.id)}
59.                 aria-pressed={isSelected}
60.                 className={`w-full text-left rounded-xl border px-4 py-2.5 font-medium text-sm transition-colors flex items-center ${
61.                   isSelected
62.                     ? 'border-wine-400 bg-wine-100 text-wine-800 ring-2 ring-wine-400'
63.                     : 'border-slate-200 bg-white text-slate-700 hover:border-wine-300 hover:bg-wine-50'
64.                 }`}
65.               >
66.                 <span className="font-bold text-slate-400 mr-2">
67.                   {String.fromCharCode(65 + i)}.
68.                 </span>
69.                 {opt.text}
70.               </button>
71.             );
72.           })}
73.         </div>
74. 
75.         {selectedOptionId && (
76.           <p className="text-center text-slate-400 text-sm">
77.             Selection recorded — you can change it until the host reveals.
78.           </p>
79.         )}
80.       </div>
81.     </div>
82.   );
83. }
84. 
