14. import { test, expect } from '@playwright/test';
15. 
16. test.describe('Mobile UX', () => {
17.   test.beforeEach(async ({ page }) => {
18.     await page.goto('/');
19.   });
20. 
21.   test('Home page — buttons are tappable (≥ 44 px) @mobile @smoke', async ({ page }) => {
22.     // Scope to main to avoid NavBar links (e.g. "Host a Game") matching the same name
23.     const main = page.getByRole('main');
24.     const hostBtn = main.getByRole('link', { name: /host/i });
25.     const joinBtn = main.getByRole('link', { name: /join|participant/i });
26. 
27.     for (const btn of [hostBtn, joinBtn]) {
28.       const box = await btn.boundingBox();
29.       expect(box, 'Button must be visible').not.toBeNull();
30.       expect(
31.         box!.height,
32.         `Button "${await btn.textContent()}" height must be ≥ 44 px`,
33.       ).toBeGreaterThanOrEqual(44);
34.       expect(
35.         box!.width,
36.         `Button "${await btn.textContent()}" width must be ≥ 44 px`,
37.       ).toBeGreaterThanOrEqual(44);
38.     }
39.   });
40. 
41.   test('Join page — session code input uses numeric keyboard @mobile @smoke', async ({ page }) => {
42.     await page.goto('/play');
43. 
