45.     const input = page.getByLabel(/tasting code/i);
46.     await expect(input).toBeVisible();
47. 
48.     const inputMode = await input.getAttribute('inputmode');
49.     expect(
50.       inputMode,
51.       'Tasting code field must have inputmode="numeric" so mobile users get a numpad',
52.     ).toBe('numeric');
53.   });
54. 
55.   test('Join flow completes on mobile viewport @mobile', async ({ page }) => {
56.     // We need a real session to join — skip gracefully if PartyKit is unavailable
57.     const partyRes = await page.request.get('http://localhost:1999/').catch(() => null);
58.     if (!partyRes || partyRes.status() >= 500) {
59.       test.skip(true, 'PartyKit not reachable — skipping mobile join flow');
60.     }
61. 
62.     await page.goto('/play');
63. 
64.     await test.step('Navigate to join page', async () => {
65.       await expect(page.getByLabel(/tasting code/i)).toBeVisible();
