71.       const clientWidth: number = await page.evaluate(() => document.documentElement.clientWidth);
72.       expect(
73.         scrollWidth,
74.         'Page must not require horizontal scrolling on mobile',
75.       ).toBeLessThanOrEqual(clientWidth + 1); // +1 px tolerance for sub-pixel rounding
76.     });
77.   });
78. 
79.   test('NavBar URL span is visible at 375px viewport (no hidden class) @mobile @smoke', async ({ page }) => {
