1. import { test, expect, type Browser } from '@playwright/test';
2. 
3. // ─── Helpers ──────────────────────────────────────────────────────────────────
4. 
5. /** Fill and submit the host form; returns the session code displayed in the lobby. */
6. async function hostCreateSession(browser: Browser) {
7.   const hostCtx = await browser.newContext();
8.   const hostPage = await hostCtx.newPage();
9.   await hostPage.goto('/host');
10. 
11.   // New dashboard phase — click New Session to get to the form
12.   const newSessionBtn = hostPage.getByRole('button', { name: /new blind testing/i });
13.   if (await newSessionBtn.waitFor({ state: 'visible', timeout: 8000 }).then(() => true).catch(() => false)) {
14.     await newSessionBtn.click();
15.   }
16.   await expect(hostPage.getByRole('button', { name: /create tasting/i })).toBeVisible();
17. 
18.   // All form fields have valid default values — only override wine name for test identity.
19.   await hostPage.getByLabel('Wine 1 Wine Name — correct answer').fill('Grand Cru Test');
20.   await hostPage.keyboard.press('Escape');
21.   await hostPage.getByRole('button', { name: /create tasting/i }).click();
22. 
23.   // The visible session code is rendered with an aria-label like "Tasting code: 6 1 8 3".
24.   // Read the aria-label and extract digits to avoid matching the share URL that contains the code.
25.   const codeEl = hostPage.locator('[aria-label^="Tasting code"]');
26.   await expect(codeEl.first()).toBeVisible();
27.   const aria = (await codeEl.first().getAttribute('aria-label')) ?? '';
28.   const code = aria.replace(/\D/g, '');
29. 
30.   return { hostPage, hostCtx, code };
31. }
32. 
33. /** Advance host through a single question: reveal → question_leaderboard → next question. */
34. async function revealAndAdvance(hostPage: import('@playwright/test').Page) {
35.   await hostPage.getByRole('button', { name: /reveal answer/i }).click();
36.   // After reveal, "Next" button appears → goes to question leaderboard
37.   const nextBtn = hostPage.getByRole('button', { name: /next/i });
38.   await expect(nextBtn).toBeVisible();
39.   await nextBtn.click();
40.   // After question leaderboard, "Next Question" or "See Round Results" appears
41.   const nextBtn2 = hostPage.getByRole('button', { name: /next question|see round results/i });
42.   await expect(nextBtn2).toBeVisible();
43.   await nextBtn2.click();
44. }
45. 
46. // ─── Tests ────────────────────────────────────────────────────────────────────
47. 
48. test.describe('Full Game Flow', () => {
49.   test('Full game - one wine, one participant reaches final leaderboard', async ({ browser }) => {
50.     const { hostPage, hostCtx, code } = await test.step('Host creates session', async () => {
51.       return hostCreateSession(browser);
52.     });
53. 
54.     const participantCtx = await browser.newContext();
55.     const participantPage = await participantCtx.newPage();
56. 
57.     try {
58.       await test.step('Participant joins session', async () => {
59.         await participantPage.goto('/play');
60.         await expect(participantPage.getByRole('button', { name: /join/i })).toBeVisible();
61.         await participantPage.getByLabel('Tasting code').fill(code);
62.         await participantPage.getByRole('button', { name: /join/i }).click();
63.         // Participant is now in lobby — pseudonym should appear
64.         await expect(participantPage.getByText(/waiting for the host/i).last()).toBeVisible();
65.       });
66. 
67.       await test.step('Host starts the game', async () => {
68.         await hostPage.getByRole('button', { name: /start game/i }).click();
69.         // Both should see Q1
70.         await expect(hostPage.getByRole('button', { name: /reveal answer/i })).toBeVisible();
71.         await expect(participantPage.getByRole('button').first()).toBeVisible();
72.       });
73. 
74.       await test.step('Participant answers Q1 (first option)', async () => {
75.         // Pick the first answer option button on the participant view
76.         await participantPage.getByRole('button').first().click();
77.         // After answering, the button area shows a selection confirmation
78.         await expect(participantPage.getByText(/selection recorded/i).first()).toBeVisible();
79.       });
80. 
81.       await test.step('Host reveals Q1 and advances to Q2', async () => {
82.         await revealAndAdvance(hostPage);
83.       });
84. 
85.       await test.step('Host advances through Q2, Q3, Q4, Q5 without answering', async () => {
86.         for (let q = 2; q <= 5; q++) {
87.           await expect(hostPage.getByRole('button', { name: /reveal answer/i })).toBeVisible();
88.           await revealAndAdvance(hostPage);
89.         }
90.       });
91. 
92.       await test.step('Round leaderboard appears after all questions answered', async () => {
93.         // After Q4 advance, we may land on round leaderboard before final
94.         // In a 1-wine session the "next" after round leaderboard goes to final
95.         const nextOrFinal = hostPage.getByRole('button', { name: /next|final/i }).first();
96.         const visible = await nextOrFinal.waitFor({ state: 'visible', timeout: 10_000 }).then(() => true).catch(() => false);
97.         if (visible) {
98.           await nextOrFinal.click();
99.         }
100.       });
101. 
102.       await test.step('Final leaderboard is shown with 1 ranking', async () => {
103.         await expect(hostPage.getByText(/final results/i)).toBeVisible();
104.         // Rankings list (ol > li items)
105.         await expect(hostPage.getByRole('listitem')).toHaveCount(1);
106. 
107.         // Participant also sees the final leaderboard
108.         await expect(participantPage.getByText(/final/i).last()).toBeVisible();
109.       });
110. 
111.       await test.step('Participant sees "Play Another Tasting" button after game ends @full', async () => {
112.         await expect(participantPage.getByRole('button', { name: /play another tasting/i })).toBeVisible({ timeout: 10_000 });
113.       });
114. 
115.       await test.step('Participant clicks "Play Another Tasting" — arrives at clean join form @full', async () => {
116.         await participantPage.getByRole('button', { name: /play another tasting/i }).click();
117.         await expect(participantPage).toHaveURL(/\/play/);
118.         await expect(participantPage.getByRole('textbox')).toHaveValue('');
119.       });
120.     } finally {
121.       await participantCtx.close();
122.       await hostCtx.close();
123.     }
124.   });
125. 
126.   test('Full game - error path: late joiner after game start is rejected', async ({ browser }) => {
127.     const { hostPage, hostCtx, code } = await test.step('Host creates session', async () => {
